public object FfiConverterTypeMsgReceiver: FfiConverter<MsgReceiver, Pointer> {
    internal val handleMap = UniffiHandleMap<MsgReceiver>()

    override fun lower(value: MsgReceiver): Pointer {
        return Pointer(handleMap.insert(value))
    }

    override fun lift(value: Pointer): MsgReceiver {
        return MsgReceiverImpl(value)
    }

    override fun read(buf: ByteBuffer): MsgReceiver {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: MsgReceiver) = 8UL

    override fun write(value: MsgReceiver, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}


// This template implements a class for working with a Rust struct via a Pointer/Arc<T>
// to the live Rust struct on the other side of the FFI.
//
